<template><div><el-card><div class="toolbar"><h2>线路管理</h2><el-input v-model="q.keyword" placeholder="关键字" style="width:200px"/><el-button type="primary" @click="load">查询</el-button><el-button type="success" @click="open({})">新增</el-button></div><el-table :data="list"><el-table-column prop="routeName" label="线路"/><el-table-column prop="spotId" label="景点ID"/><el-table-column prop="days" label="天数"/><el-table-column prop="price" label="价格"/><el-table-column label="状态"><template #default="{row}"><StatusTag :value="row.status"/></template></el-table-column><el-table-column label="操作" width="220"><template #default="{row}"><el-button link @click="routeApi.off(row.id).then(load)">下架</el-button><el-button link @click="routeApi.on(row.id).then(load)">上架</el-button><el-button link @click="open(row)">编辑</el-button><el-button link type="danger" @click="del(row.id)">删除</el-button></template></el-table-column></el-table></el-card><el-dialog v-model="show" title="线路管理"><el-form :model="form" label-width="100px"><el-form-item label="线路名"><el-input v-model="form.routeName"/></el-form-item><el-form-item label="景点ID"><el-input-number v-model="form.spotId"/></el-form-item><el-form-item label="天数"><el-input-number v-model="form.days"/></el-form-item><el-form-item label="价格"><el-input-number v-model="form.price"/></el-form-item><el-form-item label="人数上限"><el-input-number v-model="form.maxPeople"/></el-form-item><el-form-item label="封面"><el-input v-model="form.coverImage"/></el-form-item><el-form-item label="行程"><el-input type="textarea" v-model="form.itinerary"/></el-form-item><el-form-item label="描述"><el-input type="textarea" v-model="form.description"/></el-form-item><el-form-item label="状态"><el-select v-model="form.status"><el-option label="上架" value="ON_SALE"/><el-option label="下架" value="OFF_SALE"/></el-select></el-form-item></el-form><template #footer><el-button @click="show=false">取消</el-button><el-button type="primary" @click="save">保存</el-button></template></el-dialog></div></template>
<script setup>import { reactive,ref,onMounted } from 'vue'; import { ElMessage,ElMessageBox } from 'element-plus'; import { routeApi } from '../../api/modules'; import StatusTag from '../../components/StatusTag.vue'; const q=reactive({page:1,size:20}),list=ref([]),show=ref(false),form=reactive({}); async function load(){const d=await routeApi.list(q); list.value=d.records||d} function open(row){Object.keys(form).forEach(k=>delete form[k]); Object.assign(form,row); show.value=true} async function save(){form.id?await routeApi.update(form.id,form):await routeApi.add(form); ElMessage.success('保存成功'); show.value=false; load()} async function del(id){await ElMessageBox.confirm('确认删除？'); await routeApi.del(id); load()} onMounted(load)</script>
